Here's how to handle draft persistence using MAUI's app lifecycle events and `Preferences`:

**In your `NotePage.xaml.cs`:**

```csharp
public partial class NotePage : ContentPage
{
    private const string DraftKey = "note_draft";

    public NotePage()
    {
        InitializeComponent();

        // Subscribe to lifecycle events
        App.Current.Windows[0].Resuming += OnResuming;
        App.Current.Windows[0].Deactivated += OnDeactivated;
    }

    protected override void OnAppearing()
    {
        base.OnAppearing();
        RestoreDraft();
    }

    private void OnDeactivated(object sender, EventArgs e)
    {
        SaveDraft();
    }

    private void OnResuming(object sender, EventArgs e)
    {
        RestoreDraft();
    }

    private void SaveDraft()
    {
        Preferences.Set(DraftKey, NoteEditor.Text ?? string.Empty);
    }

    private void RestoreDraft()
    {
        NoteEditor.Text = Preferences.Get(DraftKey, string.Empty);
    }

    public void ClearDraft()
    {
        Preferences.Remove(DraftKey);
    }

    // Prevent memory leaks
    protected override void OnDisappearing()
    {
        base.OnDisappearing();
        App.Current.Windows[0].Resuming -= OnResuming;
        App.Current.Windows[0].Deactivated -= OnDeactivated;
    }
}
```

**Key points:**

- **`Deactivated`** fires when the app goes to the background — save here.
- **`Resuming`** fires when the app returns — restore here.
- **`Preferences`** is a simple key-value store that persists across sessions. For larger text, use `SecureStorage` or file I/O instead.
- Always **unsubscribe** from events in `OnDisappearing` to avoid leaks.
- Call `ClearDraft()` after the user explicitly saves their note.
